class ThreadResumeParams(BaseModel):
    """There are three ways to resume a thread: 1. By thread_id: load the thread from disk by thread_id and resume it. 2. By history: instantiate the thread from memory and resume it. 3. By path: load the thread from disk by path and resume it.

    The precedence is: history > path > thread_id. If using history or path, the thread_id param will be ignored.

    Prefer using thread_id whenever possible.
    """

    approval_policy: AskForApproval | None = Field(None, alias="approvalPolicy")
    approvals_reviewer: ApprovalsReviewer | None = Field(None, alias="approvalsReviewer")
    """
    Override where approval requests are routed for review on this thread and subsequent turns.
    """
    base_instructions: str | None = Field(None, alias="baseInstructions")
    config: dict[str, Any] | None = None
    cwd: str | None = None
    developer_instructions: str | None = Field(None, alias="developerInstructions")
    history: list[ResponseItem] | None = None
    """
    [UNSTABLE] FOR CODEX CLOUD - DO NOT USE. If specified, the thread will be resumed with the provided history instead of loaded from disk.
    """
    model: str | None = None
    """
    Configuration overrides for the resumed thread, if any.
    """
    model_provider: str | None = Field(None, alias="modelProvider")
    path: str | None = None
    """
    [UNSTABLE] Specify the rollout path to resume from. If specified, the thread_id param will be ignored.
    """
    persist_extended_history: bool | None = Field(False, alias="persistExtendedHistory")
    """
    If true, persist additional rollout EventMsg variants required to reconstruct a richer thread history on subsequent resume/fork/read.
    """
    personality: Personality | None = None
    sandbox: SandboxMode | None = None
    service_tier: ServiceTier | None = Field(None, alias="serviceTier")
    thread_id: str = Field(..., alias="threadId")


